			AND COALESCE(AA.USE_YN, 'Y') = 'Y'


			AND COALESCE(AA.DEL_YN, 'N') = 'N'



    		AND AA.BANNER_MST_CD 	= #{bannerMstCd	, jdbcType=VARCHAR}



    		AND AA.BANNER_SEQ 	= #{bannerSeq	, jdbcType=INTEGER}

mapper.select:
    	/* com.erns.coching.banner.mapper.BannerDAO.getList */

    	SELECT B.* FROM (
			SELECT A.*,ROW_NUMBER() OVER () AS RN, COUNT(*) OVER() TOTAL FROM (
				SELECT

				FROM T_BANNER_INF AA



				ORDER BY AA.SORT_ORD
			) A
		) B

	    	WHERE RN BETWEEN (#{offset} + 1) AND #{offset} + #{rowSize}

/* com.erns.coching.banner.mapper.BannerDAO.load */
SELECT
, BM.BANNER_TYPE , BM.BANNER_MST_NAME FROM T_BANNER_INF AA JOIN T_BANNER_MST BM ON AA.BANNER_MST_CD = BM.BANNER_MST_CD
AND AA.BANNER_SEQ = #{bannerSeq , jdbcType=INTEGER}

mapper.insert:
    	/* com.erns.coching.banner.mapper.BannerDAO.insert */


			SELECT nextval('seq_t_banner_inf')


    	INSERT INTO T_BANNER_INF (
    		  BANNER_SEQ
			, BANNER_MST_CD
			, BANNER_NAME
			, FROM_DATE
			, TO_DATE
			, BANNER_DESC
			, BANNER_URL
			, BANNER_WIDTH
			, BANNER_HEIGHT
			, CLICKS
			, USE_YN
			, DEL_YN

			, RGTR
			, RGT_DTTM
			, CHNR
			, CHNG_DTTM
    	) VALUES (
			  #{bannerSeq	, jdbcType=INTEGER}
			, #{bannerMstCd , jdbcType=VARCHAR}
			, #{bannerName	, jdbcType=VARCHAR}
			, #{fromDate	, jdbcType=VARCHAR}
			, #{toDate		, jdbcType=VARCHAR}
			, #{bannerDesc	, jdbcType=VARCHAR}
			, #{bannerUrl	, jdbcType=VARCHAR}
			, #{bannerWidth	, jdbcType=INTEGER}
			, #{bannerHeight, jdbcType=INTEGER}
			, #{clicks		, jdbcType=INTEGER}
			, COALESCE(#{useYn	, jdbcType=CHAR}, 'Y')
			, COALESCE(#{delYn	, jdbcType=CHAR}, 'N')

			, #{rgtr	, jdbcType=INTEGER}
			, now()
			, #{chnr	, jdbcType=INTEGER}
			, now()
    	)

mapper.update:
    	/* com.erns.coching.banner.mapper.BannerDAO.update */

    	UPDATE T_BANNER_INF SET
			  BANNER_MST_CD     	= #{bannerMstCd , jdbcType=VARCHAR}
			, BANNER_NAME       	= #{bannerName	, jdbcType=VARCHAR}
			, FROM_DATE        		= #{fromDate	, jdbcType=VARCHAR}
			, TO_DATE          		= #{toDate		, jdbcType=VARCHAR}
			, BANNER_DESC       	= #{bannerDesc	, jdbcType=VARCHAR}
			, BANNER_URL        	= #{bannerUrl	, jdbcType=VARCHAR}
			, BANNER_WIDTH      	= #{bannerWidth	, jdbcType=INTEGER}
			, BANNER_HEIGHT     	= #{bannerHeight, jdbcType=INTEGER}
			, CLICKS           	 	= #{clicks		, jdbcType=INTEGER}
			, USE_YN            	= COALESCE(#{useYn	, jdbcType=CHAR}, 'Y')
			, DEL_YN            	= COALESCE(#{delYn	, jdbcType=CHAR}, 'N')

			, CHNR 		 			= #{chnr, jdbcType=INTEGER}
			, CHNG_DTTM  			= now()

			AND BANNER_SEQ 			= #{bannerSeq	, jdbcType=INTEGER}

    	/* com.erns.coching.banner.mapper.BannerDAO.updateUseYn */

    	UPDATE T_BANNER_INF SET
			  USE_YN            = COALESCE(#{useYn	, jdbcType=CHAR}, 'N')

			, CHNR 		 	= #{chnr	, jdbcType=INTEGER}
			, CHNG_DTTM  	= now()

			AND BANNER_MST_CD 	= #{bannerMstCd, jdbcType=VARCHAR}
			AND BANNER_SEQ 		= #{bannerSeq, jdbcType=INTEGER}

    	/* com.erns.coching.banner.mapper.BannerDAO.updateDelYn */

    	UPDATE T_BANNER_INF SET
			  DEL_YN            = COALESCE(#{delYn	, jdbcType=CHAR}, 'N')

			, CHNR 		 	= #{chnr	, jdbcType=INTEGER}
			, CHNG_DTTM  	= now()

			AND BANNER_MST_CD 	= #{bannerMstCd, jdbcType=VARCHAR}
			AND BANNER_SEQ 		= #{bannerSeq, jdbcType=INTEGER}

    	/* com.erns.coching.banner.mapper.BannerDAO.updateOrder */

    	UPDATE T_BANNER_INF SET
			  SORT_ORD      = #{sortOrd	, jdbcType=INTEGER}

			, CHNR 		 	= #{chnr	, jdbcType=INTEGER}
			, CHNG_DTTM  	= now()

			AND BANNER_SEQ 	= #{bannerSeq, jdbcType=INTEGER}

    	/* com.erns.coching.banner.mapper.BannerDAO.updateUnusedOrder */

    	UPDATE T_BANNER_INF SET
			  SORT_ORD      = 9999

			, CHNR 		 	= #{chnr	, jdbcType=INTEGER}
			, CHNG_DTTM  	= now()

			AND BANNER_MST_CD 	= #{bannerMstCd, jdbcType=VARCHAR}

mapper.delete:
/* com.erns.coching.banner.mapper.BannerDAO.delete */

DELETE FROM T_BANNER_INF

	AND BANNER_SEQ = #{bannerSeq, jdbcType=INTEGER}
